SELECT [def01-ANALISIVENDUTOITEM-PIVOT].[Country Code], [def01-ANALISIVENDUTOITEM-PIVOT].Salesperson, [def01-ANALISIVENDUTOITEM-PIVOT].CustomerName, [def01-ANALISIVENDUTOITEM-PIVOT].ClienteSpedizione AS ShipToCustomer, [def01-ANALISIVENDUTOITEM-PIVOT].ClienteSpedizione2 AS ShipToCustomer2, [def01-ANALISIVENDUTOITEM-PIVOT].IndirizzoSpedizione AS ShipToAddress, [def01-ANALISIVENDUTOITEM-PIVOT].IndirizzoSpedizione2 AS ShipToAddress2, [def01-ANALISIVENDUTOITEM-PIVOT].CittaSpedizione AS ShipToCity, [def01-ANALISIVENDUTOITEM-PIVOT].CodicePostaleSpedizione AS ShipToCap, [def01-ANALISIVENDUTOITEM-PIVOT].CountySpedizione AS ShipToCounty, [def01-ANALISIVENDUTOITEM-PIVOT].Article, [def01-ANALISIVENDUTOITEM-PIVOT].ColorCode, [def01-ANALISIVENDUTOITEM-PIVOT].[Assortment Code], [def01-ANALISIVENDUTOITEM-PIVOT].[Description 2], [def01-ANALISIVENDUTOITEM-PIVOT].[Requested Delivery Date], Sum(IIf([documenttype]="SALES",[QuantitySold],0)) AS QuantitySoldGross, Sum(IIf([documenttype]="SALES",[ValueSold],0)) AS valueSoldGross, Sum(IIf([delete reason]<>"" And [documenttype]="sales",[quantitysold],0)) AS QuantityCancelled, Sum(IIf([delete reason]<>"" And [documenttype]="sales",[valuesold],0)) AS ValueCancelled, Sum(IIf([delete reason]="" And [documenttype]="sales",[quantitysold],0)) AS QuantitySoldNet, Sum(IIf([delete reason]="" And [documenttype]="sales",[valuesold],0)) AS ValueSoldNet, Sum([def01-ANALISIVENDUTOITEM-PIVOT].QuantityShipped) AS QuantityShipped1, Sum([def01-ANALISIVENDUTOITEM-PIVOT].ValueShipped) AS ValueShipped1, Sum(IIf([delete reason]="" And [documenttype]="sales",[quantitysold],0))-Sum([QuantityShipped]) AS QuantityOutstanding, Sum(IIf([delete reason]="" And [documenttype]="sales",[valuesold],0))-Sum([ValueShipped]) AS ValueOutstanding, Sum([def01-ANALISIVENDUTOITEM-PIVOT].QuantityReadyForShippingRilasciate) AS QuantityReadyForShippingValidated, Sum([def01-ANALISIVENDUTOITEM-PIVOT].ValueReadyForShippingRilasciate) AS ValueReadyForShippingValidated, Sum([def01-ANALISIVENDUTOITEM-PIVOT].QuantityReadyForShippingAperte) AS QuantityReadyForShippingBlocked, Sum([def01-ANALISIVENDUTOITEM-PIVOT].ValueReadyForShippingAperte) AS ValueReadyForShippingBlocked, Sum([def01-ANALISIVENDUTOITEM-PIVOT].QuantityReturned) AS QuantityReturned, Sum([def01-ANALISIVENDUTOITEM-PIVOT].ValueReturned) AS ValueReturned, [def01-ANALISIVENDUTOITEM-PIVOT].[Season Code], [def01-ANALISIVENDUTOITEM-PIVOT].[Trademark Code], [def01-ANALISIVENDUTOITEM-PIVOT].[Order Date] AS OrderDate
FROM [def01-ANALISIVENDUTOITEM-PIVOT]
GROUP BY [def01-ANALISIVENDUTOITEM-PIVOT].[Country Code], [def01-ANALISIVENDUTOITEM-PIVOT].Salesperson, [def01-ANALISIVENDUTOITEM-PIVOT].CustomerName, [def01-ANALISIVENDUTOITEM-PIVOT].ClienteSpedizione, [def01-ANALISIVENDUTOITEM-PIVOT].ClienteSpedizione2, [def01-ANALISIVENDUTOITEM-PIVOT].IndirizzoSpedizione, [def01-ANALISIVENDUTOITEM-PIVOT].IndirizzoSpedizione2, [def01-ANALISIVENDUTOITEM-PIVOT].CittaSpedizione, [def01-ANALISIVENDUTOITEM-PIVOT].CodicePostaleSpedizione, [def01-ANALISIVENDUTOITEM-PIVOT].CountySpedizione, [def01-ANALISIVENDUTOITEM-PIVOT].Article, [def01-ANALISIVENDUTOITEM-PIVOT].ColorCode, [def01-ANALISIVENDUTOITEM-PIVOT].[Assortment Code], [def01-ANALISIVENDUTOITEM-PIVOT].[Description 2], [def01-ANALISIVENDUTOITEM-PIVOT].[Requested Delivery Date], [def01-ANALISIVENDUTOITEM-PIVOT].[Season Code], [def01-ANALISIVENDUTOITEM-PIVOT].[Trademark Code], [def01-ANALISIVENDUTOITEM-PIVOT].[Order Date];

